\displaystyle{\begin{aligned}[t]
    \frac{5}{6} \div \left(-\frac{4}{15}\right)
        \amp = \frac{5}{6} \cdot \left(-\frac{15}{4}\right) \amp \hbox{We can divide the first denominator and the second numerator by 3.}\\
        \amp = \frac{5}{2 }\cdot\left(-\frac{5}{4}\right) \\
        \amp = -\frac{25}{8}
\end{aligned}
